import{_ as t,o as l,c as e,a4 as i}from"./chunks/framework._in6GHBg.js";const u=JSON.parse('{"title":"化学反应原理综合套路","description":"","frontmatter":{},"headers":[],"relativePath":"chemistry/Chem-Review-Routine-006-化学反应原理综合套路-V1.0-20260405.md","filePath":"chemistry/Chem-Review-Routine-006-化学反应原理综合套路-V1.0-20260405.md"}'),s={name:"chemistry/Chem-Review-Routine-006-化学反应原理综合套路-V1.0-20260405.md"};function n(r,a,o,h,p,d){return l(),e("div",null,[...a[0]||(a[0]=[i(`<h1 id="化学反应原理综合套路" tabindex="-1">化学反应原理综合套路 <a class="header-anchor" href="#化学反应原理综合套路" aria-label="Permalink to &quot;化学反应原理综合套路&quot;">​</a></h1><p><strong>高考化学压轴题——速率、平衡、电化学综合题解题模板</strong></p><hr><h2 id="题型认知" tabindex="-1">题型认知 <a class="header-anchor" href="#题型认知" aria-label="Permalink to &quot;题型认知&quot;">​</a></h2><h3 id="题目特征" tabindex="-1">题目特征 <a class="header-anchor" href="#题目特征" aria-label="Permalink to &quot;题目特征&quot;">​</a></h3><ul><li>以化工生产或科学研究为背景</li><li>同时考查反应速率、化学平衡、电化学等多个知识点</li><li>图像分析题占比高</li><li>计算量大，对数学能力要求高</li></ul><h3 id="分值分布" tabindex="-1">分值分布 <a class="header-anchor" href="#分值分布" aria-label="Permalink to &quot;分值分布&quot;">​</a></h3><ul><li>通常14-16分</li><li>4-6个小问</li><li>难度梯度明显，最后一问常为拔高题</li></ul><hr><h2 id="解题框架" tabindex="-1">解题框架 <a class="header-anchor" href="#解题框架" aria-label="Permalink to &quot;解题框架&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>读题 → 分析图像/数据 → 分段突破 → 综合作答</span></span></code></pre></div><hr><h2 id="第一部分-反应速率题" tabindex="-1">第一部分：反应速率题 <a class="header-anchor" href="#第一部分-反应速率题" aria-label="Permalink to &quot;第一部分：反应速率题&quot;">​</a></h2><h3 id="考点1-反应速率计算" tabindex="-1">考点1：反应速率计算 <a class="header-anchor" href="#考点1-反应速率计算" aria-label="Permalink to &quot;考点1：反应速率计算&quot;">​</a></h3><p><strong>公式</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>v = Δc/Δt</span></span>
<span class="line"><span></span></span>
<span class="line"><span>单位：mol/(L·s) 或 mol/(L·min)</span></span></code></pre></div><p><strong>注意</strong>：</p><ul><li>用不同物质表示的速率之比 = 化学计量数之比</li><li>速率都是正值</li></ul><h3 id="考点2-影响反应速率的因素" tabindex="-1">考点2：影响反应速率的因素 <a class="header-anchor" href="#考点2-影响反应速率的因素" aria-label="Permalink to &quot;考点2：影响反应速率的因素&quot;">​</a></h3><p><strong>答题模板</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>...因素增大，单位体积内...增多，有效碰撞几率增加，</span></span>
<span class="line"><span>反应速率加快。</span></span></code></pre></div><p><strong>示例</strong>：</p><ul><li>问：为什么升高温度反应速率加快？</li><li>答：升高温度，分子能量增加，活化分子百分数增大， 有效碰撞几率增加，反应速率加快。</li></ul><h3 id="考点3-速率-时间图像分析" tabindex="-1">考点3：速率-时间图像分析 <a class="header-anchor" href="#考点3-速率-时间图像分析" aria-label="Permalink to &quot;考点3：速率-时间图像分析&quot;">​</a></h3><p><strong>图像类型</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:left;">图像特征</th><th style="text-align:left;">可能原因</th></tr></thead><tbody><tr><td style="text-align:left;">某时刻正逆速率都突增</td><td style="text-align:left;">浓度增大/压强增大（气体）</td></tr><tr><td style="text-align:left;">某时刻正逆速率都突减</td><td style="text-align:left;">浓度减小/压强减小（气体）</td></tr><tr><td style="text-align:left;">某时刻速率逐渐变化</td><td style="text-align:left;">温度改变</td></tr><tr><td style="text-align:left;">正逆速率同倍数变化</td><td style="text-align:left;">加催化剂/压强改变（等体反应）</td></tr><tr><td style="text-align:left;">某时刻只有正速率或逆速率突变</td><td style="text-align:left;">移去产物/加入反应物</td></tr></tbody></table><hr><h2 id="第二部分-化学平衡题" tabindex="-1">第二部分：化学平衡题 <a class="header-anchor" href="#第二部分-化学平衡题" aria-label="Permalink to &quot;第二部分：化学平衡题&quot;">​</a></h2><h3 id="考点1-平衡状态判断" tabindex="-1">考点1：平衡状态判断 <a class="header-anchor" href="#考点1-平衡状态判断" aria-label="Permalink to &quot;考点1：平衡状态判断&quot;">​</a></h3><p><strong>平衡标志</strong>（正逆速率相等，各物质浓度不变）：</p><p><strong>直接标志</strong>：</p><ul><li>正反应速率 = 逆反应速率</li><li>各物质浓度不再变化</li></ul><p><strong>间接标志</strong>（对特定反应）：</p><ul><li>某物质的生成速率 = 消耗速率</li><li>各物质的百分含量不变</li><li>体系压强不变（气体分子数变化的反应）</li><li>混合气体平均相对分子质量不变</li><li>体系颜色不变（有颜色物质参与的反应）</li></ul><h3 id="考点2-勒夏特列原理应用" tabindex="-1">考点2：勒夏特列原理应用 <a class="header-anchor" href="#考点2-勒夏特列原理应用" aria-label="Permalink to &quot;考点2：勒夏特列原理应用&quot;">​</a></h3><p><strong>判断平衡移动方向</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:left;">改变条件</th><th style="text-align:left;">平衡移动方向</th></tr></thead><tbody><tr><td style="text-align:left;">增大反应物浓度</td><td style="text-align:left;">正向移动</td></tr><tr><td style="text-align:left;">减小生成物浓度</td><td style="text-align:left;">正向移动</td></tr><tr><td style="text-align:left;">增大压强（气体）</td><td style="text-align:left;">向气体分子数少的方向移动</td></tr><tr><td style="text-align:left;">升高温度</td><td style="text-align:left;">向吸热方向移动</td></tr><tr><td style="text-align:left;">加催化剂</td><td style="text-align:left;">不移动</td></tr></tbody></table><h3 id="考点3-平衡常数计算" tabindex="-1">考点3：平衡常数计算 <a class="header-anchor" href="#考点3-平衡常数计算" aria-label="Permalink to &quot;考点3：平衡常数计算&quot;">​</a></h3><p><strong>步骤（三段式）</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>         aA   +   bB   ⇌   cC   +   dD</span></span>
<span class="line"><span>起始     n₁        n₂        0        0</span></span>
<span class="line"><span>转化    -ax       -bx       +cx      +dx</span></span>
<span class="line"><span>平衡   n₁-ax     n₂-bx      cx       dx</span></span></code></pre></div><p><strong>平衡常数表达式</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>K = [C]ᶜ[D]ᵈ / [A]ᵃ[B]ᵇ</span></span></code></pre></div><p><strong>注意</strong>：</p><ul><li>固体和纯液体浓度视为1，不写入表达式</li><li>K只与温度有关</li></ul><h3 id="考点4-平衡图像分析" tabindex="-1">考点4：平衡图像分析 <a class="header-anchor" href="#考点4-平衡图像分析" aria-label="Permalink to &quot;考点4：平衡图像分析&quot;">​</a></h3><p><strong>转化率-温度图</strong>：</p><ul><li>升温转化率增大 → 正反应吸热</li><li>升温转化率减小 → 正反应放热</li></ul><p><strong>转化率-压强图</strong>：</p><ul><li>加压转化率增大 → 正向气体分子数减少</li><li>加压转化率减小 → 正向气体分子数增加</li></ul><p><strong>「先拐先平数值大」</strong>：</p><ul><li>图像先拐弯的曲线 → 温度高或压强大</li></ul><hr><h2 id="第三部分-电化学题" tabindex="-1">第三部分：电化学题 <a class="header-anchor" href="#第三部分-电化学题" aria-label="Permalink to &quot;第三部分：电化学题&quot;">​</a></h2><h3 id="考点1-原电池原理" tabindex="-1">考点1：原电池原理 <a class="header-anchor" href="#考点1-原电池原理" aria-label="Permalink to &quot;考点1：原电池原理&quot;">​</a></h3><p><strong>形成条件</strong>：</p><ol><li>两种活泼性不同的电极</li><li>电解质溶液</li><li>闭合回路</li><li>自发进行的氧化还原反应</li></ol><p><strong>工作原理</strong>：</p><ul><li>负极：失电子，氧化反应</li><li>正极：得电子，还原反应</li><li>电子从负极经外电路流向正极</li></ul><h3 id="考点2-电解池原理" tabindex="-1">考点2：电解池原理 <a class="header-anchor" href="#考点2-电解池原理" aria-label="Permalink to &quot;考点2：电解池原理&quot;">​</a></h3><p><strong>工作原理</strong>：</p><ul><li>阳极：与电源正极相连，失电子，氧化反应</li><li>阴极：与电源负极相连，得电子，还原反应</li></ul><p><strong>离子放电顺序</strong>：</p><ul><li>阳极：S²⁻ &gt; I⁻ &gt; Br⁻ &gt; Cl⁻ &gt; OH⁻ &gt; 含氧酸根</li><li>阴极：Ag⁺ &gt; Fe³⁺ &gt; Cu²⁺ &gt; H⁺ &gt; Fe²⁺ &gt; Zn²⁺ &gt; ...</li></ul><h3 id="考点3-电极反应式书写" tabindex="-1">考点3：电极反应式书写 <a class="header-anchor" href="#考点3-电极反应式书写" aria-label="Permalink to &quot;考点3：电极反应式书写&quot;">​</a></h3><p><strong>步骤</strong>：</p><ol><li>确定电极（阳极/阴极）</li><li>确定反应物</li><li>写出产物</li><li>配平（原子守恒→电荷守恒）</li></ol><p><strong>示例</strong>（电解CuCl₂溶液）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>阳极：2Cl⁻ - 2e⁻ = Cl₂↑</span></span>
<span class="line"><span>阴极：Cu²⁺ + 2e⁻ = Cu</span></span></code></pre></div><p><strong>配平技巧</strong>：</p><ul><li>酸性溶液用H⁺配平电荷</li><li>碱性溶液用OH⁻配平电荷</li><li>用H₂O配平原子</li></ul><hr><h2 id="第四部分-综合题解题策略" tabindex="-1">第四部分：综合题解题策略 <a class="header-anchor" href="#第四部分-综合题解题策略" aria-label="Permalink to &quot;第四部分：综合题解题策略&quot;">​</a></h2><h3 id="步骤1-识别考点" tabindex="-1">步骤1：识别考点 <a class="header-anchor" href="#步骤1-识别考点" aria-label="Permalink to &quot;步骤1：识别考点&quot;">​</a></h3><p>读题时标注：</p><ul><li>「速率」→ 速率计算/影响因素</li><li>「平衡」→ 平衡移动/K计算</li><li>「电极」→ 电化学</li></ul><h3 id="步骤2-提取数据" tabindex="-1">步骤2：提取数据 <a class="header-anchor" href="#步骤2-提取数据" aria-label="Permalink to &quot;步骤2：提取数据&quot;">​</a></h3><p>从题目和图像中提取：</p><ul><li>起始浓度/物质的量</li><li>平衡浓度/转化率</li><li>温度、压强等条件</li></ul><h3 id="步骤3-分段突破" tabindex="-1">步骤3：分段突破 <a class="header-anchor" href="#步骤3-分段突破" aria-label="Permalink to &quot;步骤3：分段突破&quot;">​</a></h3><p>每个小问独立作答：</p><ul><li>速率题用速率公式</li><li>平衡题用三段式</li><li>电化学题先判断正负极/阴阳极</li></ul><h3 id="步骤4-综合联系" tabindex="-1">步骤4：综合联系 <a class="header-anchor" href="#步骤4-综合联系" aria-label="Permalink to &quot;步骤4：综合联系&quot;">​</a></h3><p>注意前后问的关联：</p><ul><li>前一问的转化率可能用于后一计算</li><li>温度对速率和平衡都有影响</li></ul><hr><h2 id="高频计算题型" tabindex="-1">高频计算题型 <a class="header-anchor" href="#高频计算题型" aria-label="Permalink to &quot;高频计算题型&quot;">​</a></h2><h3 id="题型1-转化率计算" tabindex="-1">题型1：转化率计算 <a class="header-anchor" href="#题型1-转化率计算" aria-label="Permalink to &quot;题型1：转化率计算&quot;">​</a></h3><p><strong>公式</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>转化率 = (已转化的量 / 起始的量) × 100%</span></span></code></pre></div><h3 id="题型2-产率计算" tabindex="-1">题型2：产率计算 <a class="header-anchor" href="#题型2-产率计算" aria-label="Permalink to &quot;题型2：产率计算&quot;">​</a></h3><p><strong>公式</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>产率 = (实际产量 / 理论产量) × 100%</span></span></code></pre></div><h3 id="题型3-电量计算" tabindex="-1">题型3：电量计算 <a class="header-anchor" href="#题型3-电量计算" aria-label="Permalink to &quot;题型3：电量计算&quot;">​</a></h3><p><strong>公式</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Q = I × t = n × F × z</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Q：电量（C）</span></span>
<span class="line"><span>I：电流（A）</span></span>
<span class="line"><span>t：时间（s）</span></span>
<span class="line"><span>n：物质的量（mol）</span></span>
<span class="line"><span>F：法拉第常数（96500 C/mol）</span></span>
<span class="line"><span>z：转移电子数</span></span></code></pre></div><hr><h2 id="faq-常见问题" tabindex="-1">FAQ（常见问题） <a class="header-anchor" href="#faq-常见问题" aria-label="Permalink to &quot;FAQ（常见问题）&quot;">​</a></h2><h3 id="q1-平衡图像题怎么快速判断吸放热" tabindex="-1">Q1：平衡图像题怎么快速判断吸放热？ <a class="header-anchor" href="#q1-平衡图像题怎么快速判断吸放热" aria-label="Permalink to &quot;Q1：平衡图像题怎么快速判断吸放热？&quot;">​</a></h3><p><strong>A</strong>：</p><ul><li>升温转化率增大 → 正反应吸热（ΔH &gt; 0）</li><li>升温转化率减小 → 正反应放热（ΔH &lt; 0）</li></ul><p>口诀：「升温向吸，降温向放」</p><h3 id="q2-电极反应式总是写不对怎么办" tabindex="-1">Q2：电极反应式总是写不对怎么办？ <a class="header-anchor" href="#q2-电极反应式总是写不对怎么办" aria-label="Permalink to &quot;Q2：电极反应式总是写不对怎么办？&quot;">​</a></h3><p><strong>A</strong>：</p><ol><li>先确定是阳极还是阴极（阳极氧化，阴极还原）</li><li>确定反应物（溶液中的离子或电极本身）</li><li>写出产物</li><li>先用H₂O配平原子，再用H⁺/OH⁻配平电荷</li><li>最后用e⁻配平电子</li></ol><h3 id="q3-三段式计算总是出错怎么办" tabindex="-1">Q3：三段式计算总是出错怎么办？ <a class="header-anchor" href="#q3-三段式计算总是出错怎么办" aria-label="Permalink to &quot;Q3：三段式计算总是出错怎么办？&quot;">​</a></h3><p><strong>A</strong>：</p><ul><li>规范格式：起始、转化、平衡三行</li><li>注意单位统一（都用mol或都用mol/L）</li><li>转化量与化学计量数成正比</li><li>算完检查：起始 = 平衡 + 转化</li></ul><h3 id="q4-等效平衡怎么判断" tabindex="-1">Q4：等效平衡怎么判断？ <a class="header-anchor" href="#q4-等效平衡怎么判断" aria-label="Permalink to &quot;Q4：等效平衡怎么判断？&quot;">​</a></h3><p><strong>A</strong>：</p><ul><li>恒温恒容：换算成方程式同一边，物质的量相等则等效</li><li>恒温恒压：换算成方程式同一边，物质的量之比相等则等效</li><li>技巧：极端假设法（全部转化为反应物或生成物）</li></ul><hr><h2 id="实战演练-checklist" tabindex="-1">实战演练 checklist <a class="header-anchor" href="#实战演练-checklist" aria-label="Permalink to &quot;实战演练 checklist&quot;">​</a></h2><p>拿到一道反应原理综合题：</p><ul><li>[ ] 识别各小问考点（速率/平衡/电化学）</li><li>[ ] 提取图像/表格数据</li><li>[ ] 速率题：用公式 v = Δc/Δt</li><li>[ ] 平衡题：列三段式，写K表达式</li><li>[ ] 电化学题：先判断正负极/阴阳极</li><li>[ ] 计算题：带单位，检查有效数字</li></ul><hr><h2 id="文档信息" tabindex="-1">文档信息 <a class="header-anchor" href="#文档信息" aria-label="Permalink to &quot;文档信息&quot;">​</a></h2><p><strong>文档编号</strong>: Chem-Review-Routine-006<br><strong>版本</strong>: V1.0<br><strong>编制日期</strong>: 2026-04-05<br><strong>适用题型</strong>: 化学反应原理综合题（14-16分）<br><strong>配套文档</strong>: Chem-Learn-Detail-003 化学反应原理详解</p><hr><p><em>反应原理综合题是化学的压轴题，掌握三段式、电极反应式书写、图像分析三大技能。</em></p>`,119)])])}const g=t(s,[["render",n]]);export{u as __pageData,g as default};
